import DataGrid from 'devextreme/ui/data_grid'
// 그리드 옵션들을 알고 싶으면 그리드 인스턴스의 option()을 콘솔찍으면 나옵니다

import { i18n } from '@/main'
import grid from '../../store/modules/grid'

DataGrid.defaultOptions({
  options: {
    columnResizingMode: 'widget', // 사용자가 열 크기를 조정하면 UI 구성 요소의 너비가 변경됩니다. 열 너비를 백분율로 지정하면 이 모드는 무시됩니다 .
    dateSerializationFormat: 'yyyyMMdd',
    height: '1',
    // 페이지
    pager: {
      visible: true,
      allowedPageSizes: [],
      displayMode: 'full',
      showInfo: true,
      showNavigationButtons: true,
      showPageSizeSelector: true,
      infoText: '{0} / {1} ({2} 개)'
    },
    paging: {
      enabled: true,
      pageSize: 22
    },
    scrolling: {
      rowRenderingMode: 'virtual',
      mode :  'virtual'
    },
    // remoteOperations는 dev의 ODataStore 를 사용하여 서버랑 Dev를 연결시켜 사용하는 것임
    remoteOperations: false,
    // remoteOperations : {
    //   filtering : true,
    //   paging :true,
    //   sorting : true
    // },
    // 편집모드
    editing: {
      mode: 'batch',
      allowUpdating: true,
      selectTextOnEditStart: true
    },
    // 선택모드
    selection: {
      mode: 'multiple',
      selectAllMode: 'allPages',
      showCheckBoxesMode: 'always',
      deferred: true
    },
    // 짝수 줄 색
    rowAlternationEnabled: true,
    // 컬럼이 많아질때 가로스크롤 없이 ... 생기는것
    columnHidingEnabled: false,
    // 우측의 숨겨진 열이 열릴때 실행됨
    onAdaptiveDetailRowPreparing(e) {
      // 컬럼에 : 없애는것
      e.formOptions.showColonAfterLabel = false

      // 숨겨진열의 필수값들에 * 들어가게 추가
      e.formOptions.items.forEach(element => {
        if (element.column.cssClass == 'devest-grid-header-require') {
          if (!element.column.caption.endsWith('*')) {
            element.column.caption = element.column.caption + '*'
          }
        }
      })
    },

    onContentReady(e) {
      let gridInstance = e.component

      gridInstance.option('noDataText',i18n.t('noDataText'))
      if (gridInstance.option('isAdding')) {
        gridInstance.option('focusedRowIndex', 0)
        gridInstance.option('isAdding', false)
      }
    },

    // 모든 컬럼 툴팁 적용 (cell-template 제외)
    onCellPrepared(e) {
      if (e.rowType === 'data' && e.column) {
        e.cellElement.setAttribute('title', e.text)
      }
    },

    // 툴바 제거
    onToolbarPreparing(e) {
      e.toolbarOptions.visible = false
    },

    // // UI 컴포넌트가 처음 initial 될때 이벤트
    // onInitialized(e) {
    //   // 맨 앞 컬럼에 번호 넣어주는것
    //   setRowIndex(e.component)
    // },

    onInitialized(e) {
      // 맨 앞 컬럼에 번호 넣어주는것
      if (/Android|webOS|iPhone|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent)) console.log('모바일 번호 생략')
      else setRowIndex(e.component)
    },
    defaultPaging: true,
    isAdding: false
  }
})

// 그리드 열 추가
DataGrid.prototype.newRow = function(newRow) {
  Object.defineProperty(newRow, '__created__', { value: true, writable: true, enumerable: true, configurable: true })
  let dataSource = this.option('dataSource')
  let visibleRow = this.getVisibleRows()
  let fristRowIndex = visibleRow.length !== 0 ? dataSource.findIndex(element => element === visibleRow[0].data) : 0
  dataSource.splice(fristRowIndex !== -1 ? fristRowIndex : 0, 0, newRow)

  this.option('isAdding', true)
}

// 맨 앞 컬럼에 번호 넣어주는것
function setRowIndex(gridInstance) {
  let column = {
    name: 'No',
    caption: 'No',
    visible: true,
    alignment: 'center',
    allowEditing: false,
    width: 50,
    visibleIndex: 0
  }
  // 번호 계산해서 넣어주는것
  column.calculateDisplayValue = function(rowData) {
    let dataSource = gridInstance.option('dataSource')
    let key = gridInstance.option('keyExpr')

    // 중복된 키 값이 있는 지 확인
    let check = hasDuplicateKey(dataSource, key)
    if (check) {
      throw new Error('그리드 id 키 값 중복!!')
    }

    let isMasterDetail = gridInstance.option('masterDetail.enabled')
    if (isMasterDetail) {
      // isMasterDetail 은 렌더링 문제때문에 번호가 엉클수 있어서 신규 열은 제외 시켰음
      dataSource = dataSource.filter(element => !element.__created__)

      let index = dataSource.findIndex(element => element[key] === rowData[key]) + 1
      return index !== 0 ? index : ''
    } else {
      return dataSource.findIndex(element => element[key] === rowData[key]) + 1
    }
  }
  gridInstance.addColumn(column)
}

// 화면에따른 페이징 맞추기
function setPageCount(gridInstance) {
  //console.warn('gridInstance', gridInstance)
  // dev의 onContentReady 이벤트에 넣으면 됨
  // 그리드 내용의 DOM
  let gridContentElement = gridInstance.element().querySelector('.dx-datagrid-rowsview')
  let rowElement = gridContentElement.querySelectorAll('.dx-data-row')
  let firstRow = rowElement[0]
  let secondRow = rowElement[1]
  let targetRow = null
  // 첫번째 열의 높이는 다른 열들의 높이보다 작기때문에(포커싱때문에) 2번째열로 계산
  if (firstRow == null && secondRow == null) return
  else if (secondRow == null) targetRow = firstRow
  else targetRow = secondRow
  // 각각의 높이
  let contentHeight = gridContentElement.offsetHeight
  let rowHeight = targetRow.offsetHeight
  // 나누기
  let value = Math.floor(contentHeight / rowHeight)
  // 화면이동이 급박하게 이루어질 경우 간헐적으로 offsetHeight이 0으로 인식될 경우가 있음 그럴 경우 default로 15로 설정
  if (isNaN(value)) value = 15
  // 페이징 계산
  gridInstance.option('paging.pageSize', value)
  gridInstance.option('defaultPaging', false)

  // allowedPageSizes 에 페이지 기능 설정
  // 랜더링 관련 문제로 주석처리
  setPageSizes(gridInstance, value)
}

// 첫번째 값을 페이징 된 값으로 들어가게끔 처리
function setPageSizes(gridInstance, pageSize) {
  gridInstance.option('pager.allowedPageSizes', [pageSize, 'all'])

  // 랜더링관련 문제로 아래 부분 주석처리
  // var pager = gridInstance.getView("pagerView")._getPager();
  // var pageElement = pager._$element[0].querySelector('.dx-page-sizes');
  // // 첫번째
  // // pageElement.firstChild.innerText = `${pageSize}`
  // // 마지막
  // pageElement.lastChild.innerText = "전체"
}

// 같은 키가 있는지 확인
function hasDuplicateKey(array, key) {
  const keySet = new Set()

  for (const obj of array) {
    if (keySet.has(obj[key])) {
      return true
    }
    keySet.add(obj[key])
  }

  return false
}
