<template>
  <div>
    <!--the appropriate input should go here-->
    <!-- 베이스 데이타 그리드  BY LYJ -->
  </div>
</template>
<script>
////common component
import iCardTop from '@/components/common/iCardTop.vue'
import iPageTitle from '@/components/common/iPageTitle.vue'
import iCardVertical from '@/components/common/iCardVertical.vue'

// for datetime
import { getDateTimeFormat } from '@/utils/common.js'

//디폴트 옵션 설정 파일 포함
import '@/components/options/dxDataGridEnvs.js'
import { DxDataGrid, DxSelection, DxPaging, DxFilterRow, DxScrolling, DxColumn, DxPager, DxEditing, DxLookup } from 'devextreme-vue/data-grid'
import DxCheckBox from 'devextreme-vue/check-box'
import DxTextArea from 'devextreme-vue/text-area'
import ContextMenu from 'devextreme/ui/context_menu'

export default {
  name: 'BaseDataGrid',
  components: {
    //
    'i-card-top': iCardTop,
    'i-page-title': iPageTitle,
    'i-card-vertical': iCardVertical,
    //
    DxDataGrid,
    DxSelection,
    DxPaging,
    DxFilterRow,
    DxScrolling,
    DxColumn,
    DxPager,
    DxLookup,
    DxEditing,
    //
    DxCheckBox,
    DxTextArea
  },
  data() {
    return {
      enableEditColumn: [],
      datagridRfs: []
    }
  },
  computed: {
    DataGrids: function() {
      var instances = []
      this.datagridRefs.forEach(ref => {
        instances.push(this.$refs[ref].instance)
      })
      //return this.$refs[this.dxDataGridRef].instance
      return instances
    }
  },
  methods: {
    ///////////////////////////////////////
    /*        DataGrid Event Event       */
    ///////////////////////////////////////
    //ref에 해당하는 그리드 반환
    GetDataGrid(targetDataGridRef) {
      if(this.$refs[targetDataGridRef]){
        return this.$refs[targetDataGridRef].instance
      }
    },
    //첫번째 포커스로 이동시킴
    FocusFirstRow(datagrid) {
      datagrid.option('focusedRowIndex', -1)
      datagrid.option('focusedRowIndex', 0)
    },
    onRowUpdating(e) {
      // DataGrids.forEach(grid => {
      //   if (grid.NAME == e.component.NAME) grid.selectRows(e.key, true)
      // })
      // 편집모드가 batch가 아닌 cell 사용한다면 아래 주석 취소
      // e.components.selectRows(e.key, true)
    },
    onFocusedRowChanged(e) {
      //e.component.selectRowsByIndexes(0)
    },
    onEditingStart(e) {
      //if contains
      if (this.enableEditColumn.indexOf(e.column.dataField) > -1) {
        e.cancel = false
      } else e.cancel = true
    },
    onContentReady(e) {
      //////console.log(e)
    },
    gridInit(datagrid) {
      if(datagrid){
        datagrid.cancelEditData()
        datagrid.clearSelection()
        datagrid.collapseAdaptiveDetailRow()
        datagrid.collapseAll(-1)
      }
    },

    onEditorPreparing(e) {
      if (e.parentType == 'dataRow') {
        var valueChanged = this.onCellValueChanged

        e.editorOptions.onValueChanged = args => {
          if (e.index > -1) {
            valueChanged(args.value, e)
          }
        }
      }
      // boolean 타입 필터Row
      if (e.parentType === 'filterRow' && e.dataType === 'boolean') {
        e.editorOptions.valueExpr = 'filterValue'
        e.editorOptions.displayExpr = 'filterText'
        const trueText = e.trueText == 'true' ? 'O' : e.trueText
        const falseText = e.falseText == 'false' ? 'X' : e.falseText
        e.editorOptions.dataSource = [
          { filterValue: null, filterText: '(All)' },
          { filterValue: 'Y', filterText: trueText },
          { filterValue: 'N', filterText: falseText }
        ]
      }
    },
    onCheckValueChanged(value, cellInfo) {
      // cellInfo.setValue(cellInfo.value === 'Y' ? 'N' : 'Y')
      cellInfo.component.cellValue(cellInfo.row.rowIndex, cellInfo.column.dataField, cellInfo.value === 'Y' ? 'N' : 'Y')
      cellInfo.component.selectRows(cellInfo.row.key, true)
      cellInfo.component.updateDimensions()
    },

    onCellValueChanged(value, cellInfo) {
      // //console.log('onCellValueChanged')
      if (cellInfo.dataType == 'datetime') {
        // 날짜 맞춰서 안넣으면 시간은 0000으로 들어감
        cellInfo.setValue(getDateTimeFormat(value))
      } else {
        cellInfo.setValue(value)
      }
      cellInfo.component.selectRows(cellInfo.row.key, true)
      // this.DataGrids.forEach(grid => {
      //   //console.log(grid)
      //   if (grid.NAME == cellInfo.component.NAME) grid.selectRows(cellInfo.row.key, true)
      // })
      //this.DataGrids.saveEditData()
    },

    clearFilter(datagrid) {
      // this.DataGrids.forEach(grid => {
      //   if (grid.NAME == e.component.NAME) grid.clearFilter()
      // })

      datagrid.clearFilter()
    },

    onDropdownEditGridInitialized(e) {
      this.$nextTick(function() {
        const contextMenu = ContextMenu.getInstance(e.element.querySelector('.dx-context-menu'))
        if (contextMenu) contextMenu.option('cssClass', 'dx-dropdowneditor-overlay')
      })
    }
  }
}
</script>

<style lang="scss">
//datagrid-group-icon
.dx-datagrid-group-closed:before {
  content: '\f00b';
}

.dx-datagrid-group-opened::before {
  content: '\f074';
}
</style>
